/// <summary>
/// extension of table <c>LedgerJournalTrans_Asset</c>
/// </summary>
[ExtensionOf(tableStr(LedgerJournalTrans_Asset))]
internal final class ETGLedgerJournalTransAssetTblStr_Extension
{
}

Method.Source:
/// <summary>
/// Ensures that depreciation or depreciation adjustment transactions are not posted with a transaction date earlier than the asset's acquisition date
/// </summary>
/// <returns>
/// true if the record passes all validations and can be written; otherwise, false.
/// </returns>
public boolean validateWrite()
{
    boolean isValid = next validateWrite();

    if (isValid &&
        ETGACFParameters::find().EnableUATSmallPoints &&
        (this.TransType == AssetTransTypeJournal::Depreciation 
        || this.TransType == AssetTransTypeJournal::DepreciationAdj) &&
        this.AssetId && this.BookId)
    {
        AssetBook          assetBook          = AssetBook::find(this.AssetId, this.BookId);
        LedgerJournalTrans ledgerJournalTrans = LedgerJournalTrans::findRecId(this.RefRecId, false);

        if (ledgerJournalTrans && ledgerJournalTrans.TransDate < assetBook.AcquisitionDate)
        {
            isValid = checkFailed(strFmt("@ETG_New:AcquisitionDateAndTransDateComparison",
                    ledgerJournalTrans.TransDate, assetBook.AcquisitionDate));
        }
    }           

    return isValid;
}
